use std::sync::{Arc, Mutex};
use std::thread;

struct Inventory {
    stock: Mutex<i32>,
}

impl Inventory {
    fn new(initial_stock: i32) -> Self {
        Inventory {
            stock: Mutex::new(initial_stock),
        }
    }

    fn check_stock(&self) -> i32 {
        let stock = self.stock.lock().unwrap();
        *stock
    }

    fn decrement_stock(&self, amount: i32) -> bool {
        let mut stock = self.stock.lock().unwrap();
        if *stock >= amount {
            *stock -= amount;
            true
        } else {
            false
        }
    }
}

fn main() {
    let inventory = Arc::new(Inventory::new(100));
    let mut handles = vec![];

    for _ in 0..10 {
        let inventory_clone = Arc::clone(&inventory);
        let handle = thread::spawn(move || {
            if inventory_clone.decrement_stock(10) {
                println!("Stock decremented successfully.");
            } else {
                println!("Not enough stock to decrement.");
            }
        });
        handles.push(handle);
    }

    for handle in handles {
        handle.join().unwrap();
    }

    println!("Final stock level: {}", inventory.check_stock());
}